// nodes/apiNode.js
import { BaseNode } from './BaseNode';
import { Globe } from 'lucide-react';

export const ApiNode = ({ id, data, selected }) => {
  return (
    <BaseNode
      id={id}
      title="API Call"
      icon={Globe}
      accentColor="var(--accent-blue)"
      inputs={[{ id: 'body', label: 'body' }, { id: 'headers', label: 'headers' }]}
      outputs={[{ id: 'response', label: 'response' }, { id: 'status', label: 'status' }]}
      selected={selected}
    >
      <div style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginBottom: '4px' }}>
          <span style={{ fontWeight: 600, color: 'var(--accent-blue)', fontSize: '11px', padding: '2px 4px', background: 'rgba(59, 130, 246, 0.1)', borderRadius: '4px' }}>
            {data?.method || 'GET'}
          </span>
        </div>
        <div style={{ fontSize: '11px', color: 'var(--text-primary)', wordBreak: 'break-all' }}>
          {data?.url || 'https://api.example.com/endpoint'}
        </div>
      </div>
    </BaseNode>
  );
};
